// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Provide default unit of 'C' if not specified
  const unit = props.unit || 'C';

  // Map condition strings to weather emoji icons
  const getWeatherIcon = useCallback((condition: string): string => {
    const normalized = condition.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('rainy') || normalized.includes('rain')) return '🌧️';
    if (normalized.includes('snowy') || normalized.includes('snow')) return '❄️';
    if (normalized.includes('stormy') || normalized.includes('storm')) return '⛈️';
    if (normalized.includes('windy') || normalized.includes('wind')) return '💨';
    if (normalized.includes('fog') || normalized.includes('foggy')) return '🌫️';
    if (normalized.includes('drizzle')) return '🌦️';
    return '🌤️'; // Default partly cloudy
  }, []);

  return {
    getWeatherIcon,
    unit,
  };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24} align="stretch">
        {/* Main weather card */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={20} align="center">
            {/* City and condition header */}
            <Stack gap={8} align="center">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">{props.city}</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.condition}</Text>
            </Stack>

            {/* Large temperature display with weather icon */}
            <Stack gap={12} align="center">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)" align="center">
                 {props.temperature}°{state.unit}
              </Text>
              <Text size="3xl" color="var(--ggui-color-onSurface, #18181b)">
                {state.getWeatherIcon(props.condition)}
              </Text>
            </Stack>

            {/* Divider */}
            <Divider orientation="horizontal" margin={12} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

            {/* Weather details grid */}
            <Row gap={24} justify="center" align="center" wrap>
              <Stack gap={4} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{props.humidity}%</Text>
              </Stack>
              <Stack gap={4} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{props.windSpeed} m/s</Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-day forecast section */}
        <Stack gap={12} align="stretch">
          <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">5-Day Forecast</Heading>
          <Row gap={12} justify="start" align="stretch" wrap>
            {(props.forecast || []).map((day, index) => (
              <Card
                key={index}
                shadow="sm"
                padding={16}
                radius="md"
                style={{ flex: '1 1 120px', minWidth: '100px' }}
              >
                <Stack gap={8} align="center" justify="center">
                  {/* Day name */}
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                    {day.day || `Day ${index + 1}`}
                  </Text>

                  {/* Weather icon - use emoji if provided, otherwise derive from icon string */}
                  <Text size="2xl" color="var(--ggui-color-onSurface, #18181b)" align="center">
                    {day.icon || state.getWeatherIcon(day.condition || 'unknown')}
                  </Text>

                  {/* High/Low temperatures */}
                  <Stack gap={2} align="center">
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" weight="semibold" align="center">
                      {day.high !== undefined ? `${day.high}°${state.unit}` : 'N/A'}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                      {day.low !== undefined ? `${day.low}°${state.unit}` : 'N/A'}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // Form state
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validation helpers
  const isValidEmail = useCallback((value: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  }, []);

  const validateName = useCallback(() => {
    if (!name.trim()) {
      setNameError('Name is required');
      return false;
    }
    setNameError('');
    return true;
  }, [name]);

  const validateEmail = useCallback(() => {
    if (!email.trim()) {
      setEmailError('Email is required');
      return false;
    }
    if (!isValidEmail(email)) {
      setEmailError('Please enter a valid email address');
      return false;
    }
    setEmailError('');
    return true;
  }, [email, isValidEmail]);

  const isStep1Valid = useCallback(() => {
    return name.trim() !== '' && email.trim() !== '' && isValidEmail(email);
  }, [name, email, isValidEmail]);

  const isStep2Valid = useCallback(() => {
    return satisfaction !== '';
  }, [satisfaction]);

  const isStep3Valid = useCallback(() => {
    return true; // No required fields on step 3
  }, []);

  const isStep4Valid = useCallback(() => {
    return true; // Comments are optional
  }, []);

  const handleNext = useCallback(() => {
    if (currentStep === 1 && !validateName()) return;
    if (currentStep === 1 && !validateEmail()) return;
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, validateName, validateEmail]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleToggleFeature = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments,
    });
  }, [name, email, satisfaction, features, comments, submit]);

  const getProgressPercentage = useCallback(() => {
    return ((currentStep - 1) / 4) * 100;
  }, [currentStep]);

  return {
    submit,
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    setFeatures,
    handleToggleFeature,
    comments,
    setComments,
    nameError,
    emailError,
    validateName,
    validateEmail,
    isStep1Valid,
    isStep2Valid,
    isStep3Valid,
    isStep4Valid,
    handleNext,
    handleBack,
    handleSubmit,
    getProgressPercentage,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* Progress Bar */}
        <Stack gap={8}>
          <Row align="center" justify="between">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Step {state.currentStep} of 4
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {Math.round(state.getProgressPercentage())}%
            </Text>
          </Row>
          <Progress
            value={state.getProgressPercentage()}
            max={100}
            variant="primary"
            size="md"
            showLabel={false}
          />
        </Stack>

        {/* Step 1: Name and Email */}
        {state.currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={state.name}
                onChange={state.setName}
                error={state.nameError}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={state.email}
                onChange={state.setEmail}
                error={state.emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {state.currentStep === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={state.satisfaction}
                onChange={state.setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {state.currentStep === 3 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Which features interest you?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select all that apply
              </Text>
              <Stack gap={12}>
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.features.includes(feature)}
                    onChange={() => state.handleToggleFeature(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {state.currentStep === 4 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Any additional comments?</Heading>
              <TextArea
                label="Comments"
                placeholder="Share your thoughts..."
                value={state.comments}
                onChange={state.setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {state.currentStep === 5 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap={12}>
                <Box padding={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Full Name
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                      {state.name}
                    </Text>
                  </Stack>
                </Box>
                <Box padding={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Email Address
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                      {state.email}
                    </Text>
                  </Stack>
                </Box>
                <Box padding={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Satisfaction Rating
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                      {props.satisfactionLabels[parseInt(state.satisfaction, 10) - 1] || 'Not selected'}
                    </Text>
                  </Stack>
                </Box>
                <Box padding={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Interested Features
                    </Text>
                    <Stack direction="horizontal" gap={8} wrap>
                      {state.features.length > 0 ? (
                        state.features.map((feature) => (
                          <Badge key={feature} variant="primary" size="sm">
                            {feature}
                          </Badge>
                        ))
                      ) : (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          No features selected
                        </Text>
                      )}
                    </Stack>
                  </Stack>
                </Box>
                <Box padding={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Additional Comments
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                      {state.comments || '(No comments provided)'}
                    </Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap={12} justify="between" align="center">
          <Button
            variant="ghost"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
          {state.currentStep < 5 && (
            <Button
              variant="primary"
              onClick={state.handleNext}
              disabled={
                (state.currentStep === 1 && !state.isStep1Valid()) ||
                (state.currentStep === 2 && !state.isStep2Valid()) ||
                (state.currentStep === 3 && !state.isStep3Valid()) ||
                (state.currentStep === 4 && !state.isStep4Valid())
              }
            >
              Next
            </Button>
          )}
          {state.currentStep === 5 && (
            <Button variant="primary" onClick={state.handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/primitives';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // State management
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);

  // Update tasks when props change
  React.useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Computed values
  const tasksByColumn = React.useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    (props.columns || []).forEach((col) => {
      grouped[col.id || ''] = [];
    });
    tasks.forEach((task) => {
      const col = task.column || '';
      if (!grouped[col]) grouped[col] = [];
      grouped[col].push(task);
    });
    return grouped;
  }, [tasks, props.columns]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  // Handlers
  const handleMoveTask = useCallback(
    (taskId: string, toColumn: string) => {
      const task = tasks.find((t) => t.id === taskId);
      if (!task) return;
      setTasks((prevTasks) =>
        prevTasks.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t))
      );
      // Call action with full task data for move
      (window as any).__taskUpdate?.({ action: 'move', taskId, data: { column: toColumn } });
    },
    [tasks]
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setTasks((prevTasks) =>
        prevTasks.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
      );
      const task = tasks.find((t) => t.id === taskId);
      (window as any).__taskUpdate?.({ action: 'edit', taskId, data: { column: task?.column || '' } });
      setEditingTaskId(null);
      setEditingTitle('');
    },
    [taskUpdate, tasks]
  );

  const handleAddTask = useCallback(
    (columnId: string) => {
      if (!newTaskTitle.trim()) return;
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
      };
      setTasks((prevTasks) => [...prevTasks, newTask]);
      (window as any).__taskUpdate?.({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingToColumn(null);
    },
    [newTaskTitle, newTaskPriority]
  );

  const getPriorityColor = (priority?: string): 'success' | 'warning' | 'error' | 'default' => {
    switch (priority) {
      case 'low':
        return 'success';
      case 'medium':
        return 'warning';
      case 'high':
        return 'error';
      default:
        return 'default';
    }
  };

  return {
    tasks,
    setTasks,
    tasksByColumn,
    totalTasks,
    completedTasks,
    editingTaskId,
    setEditingTaskId,
    editingTitle,
    setEditingTitle,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    addingToColumn,
    setAddingToColumn,
    handleMoveTask,
    handleEditTask,
    handleAddTask,
    getPriorityColor,
  };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Stack gap={16} align="stretch">
      {/* Summary Bar */}
      <Card padding={16} shadow="sm">
        <Stack direction="horizontal" justify="between" align="center">
          <div>
            <Text variant="label">Tasks Summary</Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {state.completedTasks} of {state.totalTasks} completed
            </Text>
          </div>
          <Progress value={state.totalTasks > 0 ? (state.completedTasks / state.totalTasks) * 100 : 0} max={100} size="md" />
        </Stack>
      </Card>

      {/* Kanban Board */}
      <Stack direction="horizontal" gap={16} align="start">
        {(props.columns || []).map((column) => {
          const columnId = column.id || '';
          const columnTasks = state.tasksByColumn[columnId] || [];

          return (
            <Box key={columnId} style={{ flex: '1 1 300px', minWidth: 0 }}>
              {/* Column Header */}
              <Stack gap={12} align="stretch">
                <div>
                  <Stack direction="horizontal" justify="between" align="center" gap={8}>
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="default" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Stack>
                </div>

                {/* Task Cards Container */}
                <Stack gap={12} align="stretch" style={{ minHeight: '200px' }}>
                  {columnTasks.map((task) => {
                    const isEditing = state.editingTaskId === task.id;

                    return (
                      <Card key={task.id} padding={12} shadow="sm" border>
                        {isEditing ? (
                          <Stack gap={8} align="stretch">
                            <Input
                              label="Edit task"
                              value={state.editingTitle}
                              onChange={state.setEditingTitle}
                              size="sm"
                              placeholder="Task title"
                            />
                            <Stack direction="horizontal" gap={6} justify="end">
                              <Button
                                variant="ghost"
                                size="xs"
                                onClick={() => {
                                  state.setEditingTaskId(null);
                                  state.setEditingTitle('');
                                }}
                              >
                                Cancel
                              </Button>
                              <Button
                                variant="primary"
                                size="xs"
                                onClick={() => state.handleEditTask(task.id || '', state.editingTitle)}
                              >
                                Save
                              </Button>
                            </Stack>
                          </Stack>
                        ) : (
                          <Stack gap={8} align="stretch">
                            {/* Task Title */}
                            <Text
                              variant="body"
                              weight="semibold"
                              style={{
                                cursor: 'pointer',
                                wordBreak: 'break-word',
                              }}
                              as={Clickable}
                              onClick={() => {
                                state.setEditingTaskId(task.id || null);
                                state.setEditingTitle(task.title || '');
                              }}
                            >
                              {task.title || 'Untitled task'}
                            </Text>

                            {/* Priority Badge */}
                            {task.priority && (
