                    onClick={() => state.setAddingToColumn(columnId)}
                  >
                    <Icon name="plus" size={16} /> Add Task
                  </Button>
                )}
              </Stack>
            </Box>
          );
        })}
      </Stack>
    </Stack>
  );
}

