interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const q = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(q)) || (el.symbol?.toLowerCase().includes(q))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map(el => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  // Map category to color
  const getCategoryColor = useCallback((category?: string): string => {
    if (!category) return 'var(--ggui-color-outline, #d4d4d8)';
    const colors: Record<string, string> = {
      'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-200, #bae6fd)',
      'transition-metal': 'var(--ggui-color-primary-300, #7dd3fc)',
      'lanthanide': 'var(--ggui-color-success-100, #dcfce7)',
      'actinide': 'var(--ggui-color-success-200, #bbf7d0)',
      'nonmetal': 'var(--ggui-color-warning-100, #fef3c7)',
      'halogen': 'var(--ggui-color-error-100, #fee2e2)',
      'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
      'metalloid': 'var(--ggui-color-warning-200, #fde68a)',
    };
    return colors[category] || 'var(--ggui-color-surface, #fafafa)';
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getCategoryColor,
  };
}

