}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  // State for quantity selector and active tab
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const maxStock = props.product.stock ?? 0;
  const isOutOfStock = maxStock === 0;
  const isLowStock = maxStock > 0 && maxStock <= 10;

  // Handlers
  const handleQuantityChange = useCallback((newQty: number) => {
    const clamped = Math.max(1, Math.min(newQty, maxStock));
    setQuantity(clamped);
  }, [maxStock]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      const payload: ActionAddToCartPayload = { productId: props.product.id, quantity };
      props.onAddToCart?.(payload);
    }
  }, [props.product.id, quantity, props]);

  return {
    quantity,
    setQuantity: handleQuantityChange,
    activeTab,
    setActiveTab,
    maxStock,
    isOutOfStock,
    isLowStock,
    handleAddToCart,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const {
    product: {
      name = 'Product',
      price = 0,
      currency = '$',
      rating = 0,
      reviewCount = 0,
      stock = 0,
      description = '',
      specifications = [],
      reviews = [],
    } = {},
  } = props;

  // Helper: Render star rating
  const renderStars = (rate: number) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      const filledStars = Math.floor(rate);
      const hasPartial = rate % 1 !== 0;
      let iconName = 'star-outline';
      if (i <= filledStars) {
        iconName = 'star';
      } else if (i === Math.ceil(rate) && hasPartial) {
        iconName = 'star-half';
      }
      stars.push(
        <Icon key={i} name={iconName} size={16} />
      );
    }
    return stars;
  };

  // Helper: Format price
  const formattedPrice = `${currency}${price.toFixed(2)}`;

  // Helper: Parse specs and reviews from unknown[]
   const specs = (Array.isArray(specifications)
     ? specifications.filter((s) => s && typeof s === 'object' && 'key' in s && 'value' in s)
     : []
   ) as Record<string, unknown>[];
   const reviewList = (Array.isArray(reviews)
     ? reviews.filter((r) => r && typeof r === 'object' && 'author' in r && 'text' in r)
     : []
   ) as Record<string, unknown>[];

  return (
