              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              minHeight: '300px',
              '@media (max-width: 768px)': { flex: '1 1 100%' },
            }}
          >
            <Stack gap='var(--ggui-spacing-2, 8px)' align='center'>
              <Icon name='image' size={48} color='var(--ggui-color-primary-600, #0284c7)' />
              <Text variant='label' color='var(--ggui-color-primary-600, #0284c7)'>
                {name}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap='var(--ggui-spacing-4, 16px)' style={{ flex: '1 1 300px', minWidth: '280px', '@media (max-width: 768px)': { flex: '1 1 100%' } }}>
            {/* Title */}
            <Heading level={2}>{name}</Heading>

            {/* Price */}
            <Text variant='bodyLarge' weight='semibold' color='var(--ggui-color-primary-600, #0284c7)'>
              {formattedPrice}
            </Text>

            {/* Rating */}
            <Stack direction='horizontal' gap='var(--ggui-spacing-2, 8px)' align='center'>
              <Row gap='var(--ggui-spacing-1, 4px)'>
                {renderStars(rating)}
              </Row>
              <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                {rating.toFixed(1)} ({reviewCount} {reviewCount === 1 ? 'review' : 'reviews'})
              </Text>
            </Stack>

            {/* Stock Status Badge */}
            <div>
              {state.isOutOfStock ? (
                <Badge variant='error'>Out of Stock</Badge>
              ) : state.isLowStock ? (
                <Badge variant='warning'>Low Stock</Badge>
              ) : (
                <Badge variant='success' style={{ backgroundColor: 'var(--ggui-color-success-100, #dcfce7)', color: 'var(--ggui-color-success-700, #15803d)' }}>In Stock</Badge>
              )}
            </div>
          </Stack>
        </Stack>

        {/* Tab Navigation */}
        <Tabs
          items={[
            {
              key: 'description',
              label: 'Description',
              content: <Text variant='body'>{description || 'No description available.'}</Text>,
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                specs.length > 0 ? (
                  <Table
                    columns={[
                      { key: 'key', header: 'Specification', align: 'left' },
                      { key: 'value', header: 'Value', align: 'left' },
                    ]}
                    data={specs}
                    compact
                  />
                ) : (
                  <Text variant='body' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                    No specifications available.
                  </Text>
                )
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                reviewList.length > 0 ? (
                  <Stack gap='var(--ggui-spacing-4, 16px)'>
                    {reviewList.map((review: any, idx: number) => (
                      <Card key={idx} shadow='none' border={false} padding='var(--ggui-spacing-4, 16px)' radius='md'>
                        <Stack gap='var(--ggui-spacing-2, 8px)'>
                          <Row justify='between' align='center'>
                            <Stack direction='horizontal' gap='var(--ggui-spacing-2, 8px)' align='center'>
                              <Text variant='label' weight='semibold'>
                                {review.author || 'Anonymous'}
                              </Text>
                            </Stack>
                            <Row gap='var(--ggui-spacing-1, 4px)'>
                              {renderStars(review.rating || 0)}
                            </Row>
                          </Row>
                          <Text variant='body'>{review.text || ''}</Text>
                          <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                            {review.date ? new Date(review.date).toLocaleDateString() : ''}
                          </Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                ) : (
                  <Text variant='body' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                    No reviews yet.
                  </Text>
                )
              ),
            },
          ]}
          activeKey={state.activeTab}
          onChange={state.setActiveTab}
          variant='line'
        />

        {/* Bottom Section: Quantity Selector and Add to Cart */}
        <Card shadow='sm' padding='var(--ggui-spacing-4, 16px)' radius='lg'>
          <Stack gap='var(--ggui-spacing-4, 16px)' direction='horizontal' align='center'>
            {/* Quantity Selector */}
            <Stack direction='horizontal' gap='var(--ggui-spacing-2, 8px)' align='center'>
              <Text variant='label'>Quantity:</Text>
              <Button
                variant='outline'
                size='sm'
                onClick={() => state.setQuantity(state.quantity - 1)}
                disabled={state.quantity <= 1}
              >
                −
              </Button>
              <Text variant='label' style={{ minWidth: '30px', textAlign: 'center' }}>
                {state.quantity}
              </Text>
              <Button
                variant='outline'
                size='sm'
                onClick={() => state.setQuantity(state.quantity + 1)}
                disabled={state.quantity >= state.maxStock}
              >
                +
              </Button>
            </Stack>

            <Spacer size='flex' />

            {/* Add to Cart Button */}
            <Button
              variant='primary'
              size='lg'
              onClick={state.handleAddToCart}
              disabled={state.isOutOfStock}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

