import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  const [displayedStocks, setDisplayedStocks] = useState(props.stocks);
  const [lastUpdateTime, setLastUpdateTime] = useState<Date>(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());

  // Listen for real-time price updates via window event listener
  useEffect(() => {
    const handlePriceUpdate = (event: Event) => {
      const customEvent = event as CustomEvent<StreamPriceUpdate>;
      const update = customEvent.detail;
      if (update?.symbol) {
        setDisplayedStocks((prev) => {
          const updated = [...prev];
          const index = updated.findIndex((s) => s.symbol === update.symbol);
          if (index !== -1) {
            updated[index] = {
              ...updated[index],
              price: update.price ?? updated[index].price,
              change: update.change ?? updated[index].change,
              changePercent: update.changePercent ?? updated[index].changePercent,
            };
            setHighlightedSymbols((prev) => new Set(prev).add(update.symbol || ''));
            setTimeout(() => {
              setHighlightedSymbols((prev) => {
                const next = new Set(prev);
                next.delete(update.symbol || '');
                return next;
              });
            }, 1000);
          }
          return updated;
        });
        setLastUpdateTime(new Date());
      }
    };

    window.addEventListener('ggui:agent-data', handlePriceUpdate);
    return () => window.removeEventListener('ggui:agent-data', handlePriceUpdate);
  }, []);

  return { displayedStocks, lastUpdateTime, highlightedSymbols };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const { displayedStocks, lastUpdateTime, highlightedSymbols } = state;

  // Format price with 2 decimals
  const formatPrice = (price?: number) => {
    return price !== undefined ? `$${price.toFixed(2)}` : 'N/A';
  };

  // Determine color based on change
  const getChangeColor = (change?: number): string => {
    if (change === undefined) return 'var(--ggui-color-onSurface, #18181b)';
    return change >= 0
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)';
  };

  const getChangeBorderColor = (change?: number): string => {
    if (change === undefined) return 'var(--ggui-color-outline, #d4d4d8)';
    return change >= 0
      ? 'var(--ggui-color-success-200, #bbf7d0)'
      : 'var(--ggui-color-error-200, #fecaca)';
  };

  // Get arrow icon for change direction
  const getChangeArrow = (change?: number): string => {
    if (change === undefined) return '';
    return change >= 0 ? '▲' : '▼';
  };

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        {/* Header with title and last updated timestamp */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Last Updated: {lastUpdateTime.toLocaleTimeString()}
          </Text>
        </Stack>

        {/* Responsive grid of stock cards (3 on desktop, 1 on mobile) */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
          gap: 'var(--ggui-spacing-4, 16px)',
        }}>
          {displayedStocks.map((stock) => {
            const isHighlighted = highlightedSymbols.has(stock.symbol || '');
            const changeColor = getChangeColor(stock.change);
            const changeBorderColor = getChangeBorderColor(stock.change);

            return (
              <Card
                key={stock.symbol}
                padding={20}
                shadow="md"
                radius="lg"
                style={{
                  borderColor: changeBorderColor,
                  borderWidth: '1px',
                  background: isHighlighted
                    ? 'var(--ggui-color-primary-50, #f0f9ff)'
                    : 'var(--ggui-color-surface, #fafafa)',
                  transition: 'all 200ms ease-in-out',
                  boxShadow: isHighlighted ? '0 0 0 3px var(--ggui-color-primary-200, #bae6fd)' : undefined,
                }}
              >
                <Stack gap={12}>
                  {/* Ticker symbol - large, bold */}
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                    {stock.symbol || 'N/A'}
                  </Heading>

                  {/* Company name */}
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {stock.name || 'Unknown'}
                  </Text>

                  {/* Current price */}
                  <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {formatPrice(stock.price)}
                  </Text>

                  {/* Change amount and percentage with color coding and arrow */}
                  <Row align="center" gap={8}>
                    <Text variant="body" color={changeColor} weight="semibold">
                      {stock.change !== undefined
                        ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2)
                        : 'N/A'}
                    </Text>
                    <Text variant="body" color={changeColor} weight="semibold">
                      {stock.changePercent !== undefined
                        ? '(' + (stock.changePercent >= 0 ? '+' : '') + stock.changePercent.toFixed(2) + '%) ' + getChangeArrow(stock.change)
                        : 'N/A'}
                    </Text>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
    );
  }

